import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
} from "recharts";

export default function Reports() {
  const data = [
    { name: "Food", value: 5000 },
    { name: "Transport", value: 2000 },
    { name: "Shopping", value: 3000 },
  ];

  return (
    <div>
      <h1>Reports</h1>

      <PieChart width={400} height={400}>
        <Pie
          data={data}
          dataKey="value"
          outerRadius={120}
          label
        >
          {data.map((entry, index) => (
            <Cell key={index} />
          ))}
        </Pie>

        <Tooltip />
      </PieChart>
    </div>
  );
}
